interface OrvalGeneratedRequestConfig {
  url?: string;
  method?: string;
  headers?: Record<string, string>;
  params?: any;
  data?: any;
  signal?: AbortSignal;
}

/**
 * Options that the consumer of the generated hooks will need to provide
 * to the third argument of each hook call (or via a wrapper).
 */
export interface FetchClientProps extends Omit<
  RequestInit,
  "body" | "method" | "headers"
> {
  customFetch: (
    input: string | URL | globalThis.Request,
    init?: RequestInit,
  ) => Promise<globalThis.Response>;
  baseUrl: string;
}

/**
 * The `customFetchAdapter` function that Orval will use.
 * @param config Orval's generated request configuration (method, relative URL, params, data, headers).
 * @param optionsFromHook Options passed from the hook call, expected to include FetchClientProps
 *                        and any additional RequestInit properties for the fetch call.
 */
export async function customFetchAdapter<TData = any>(
  config: OrvalGeneratedRequestConfig,
  optionsFromHook?: FetchClientProps,
): Promise<TData> {
  const { url = "", method = "GET", headers, params, data, signal } = config;
  const { customFetch, baseUrl, ...additionalOptions } = optionsFromHook || {};

  if (!customFetch || !baseUrl) {
    throw new Error('customFetchAdapter requires "customFetch" and "baseUrl"');
  }

  // Build URL
  const requestUrl = new URL(
    url.replace(/^\/?/, ""),
    baseUrl.endsWith("/") ? baseUrl : `${baseUrl}/`,
  );

  // Add query params
  if (params) {
    Object.entries(params).forEach(([key, value]) => {
      if (value == null) return;
      if (Array.isArray(value)) {
        value.forEach((v) => requestUrl.searchParams.append(key, String(v)));
      } else {
        requestUrl.searchParams.append(key, String(value));
      }
    });
  }

  // Prepare request
  const reqHeaders = new Headers(headers);
  const reqBody = prepareRequestBody(data, reqHeaders);

  const requestInit: RequestInit = {
    method: method.toUpperCase(),
    headers: reqHeaders,
    body: reqBody,
    signal: signal,
    ...additionalOptions,
  };

  try {
    const response = await customFetch(requestUrl.toString(), requestInit);
    const data = await parseResponseData<TData>(response);
    if (!response.ok) {
      const error: any = new Error(
        `Request failed with status ${response.status}`,
      );
      throw error;
    }
    return data as TData;
  } catch (error: any) {
    throw error;
  }
}

// Helper functions for body and response handling
function prepareRequestBody(data: any, headers: Headers): BodyInit | undefined {
  if (!data) return;

  if (
    data instanceof FormData ||
    data instanceof URLSearchParams ||
    typeof data === "string" ||
    data instanceof Blob ||
    data instanceof ArrayBuffer ||
    data instanceof ReadableStream
  ) {
    return data as BodyInit;
  }

  if (!headers.has("Content-Type")) {
    headers.set("Content-Type", "application/json");
  }
  return JSON.stringify(data);
}

async function parseResponseData<T>(response: Response): Promise<T | null> {
  if (response.status === 204 || !response.body) return null;

  const contentType = response.headers.get("content-type") || "";

  if (contentType.includes("application/json")) {
    try {
      return await response.json();
    } catch (e) {
      console.error("Failed to parse JSON response");
    }
  } else if (contentType.includes("text/")) {
    return (await response.text()) as any;
  }

  return null;
}

export default customFetchAdapter;
